module RefModule (  
    input wire clk,  
    input wire rst,  
    input wire signal,  
    output reg edge_detected  
);  
    reg unused_signal_prev;  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            edge_detected <= 0;  
            unused_signal_prev <= 0;  
        end else begin  
            edge_detected <= (signal && !unused_signal_prev);  
            unused_signal_prev <= signal;  
        end  
    end  
endmodule
